#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        long long *rem = (long long*)calloc(N+1,sizeof(long long));
        for(int i=0;i<=N;i++) scanf("%lld",&rem[i]);
        int cur=0;
        for(int box=0; box<N; ++box){
            while(cur<=N && rem[cur]==0) ++cur;
            long long take1 = rem[cur] < K ? rem[cur] : K;
            rem[cur] -= take1;
            int c1 = cur;
            long long need = K - take1;
            int c2 = 0; long long take2 = 0;
            if(need>0){
                while(cur<=N && rem[cur]==0) ++cur;
                take2 = rem[cur] < need ? rem[cur] : need;
                rem[cur] -= take2;
                c2 = cur;
            }
            printf("%d %lld %d %lld\n", c1, take1, c2, take2);
        }
        free(rem);
    }
    return 0;
}

