import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int K = fs.nextInt();
            long[] rem = new long[N+1];
            for (int i = 0; i <= N; i++) rem[i] = fs.nextLong();
            int cur = 0;
            for (int box = 0; box < N; box++) {
                while (cur <= N && rem[cur] == 0) cur++;
                long take1 = Math.min(rem[cur], K);
                rem[cur] -= take1;
                int c1 = cur;
                long need = K - take1;
                int c2 = 0; long take2 = 0;
                if (need > 0) {
                    while (cur <= N && rem[cur] == 0) cur++;
                    take2 = Math.min(rem[cur], need);
                    rem[cur] -= take2;
                    c2 = cur;
                }
                out.append(c1).append(' ').append(take1).append(' ').append(c2).append(' ').append(take2).append('\n');
            }
        }
        System.out.print(out.toString());
    }
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c == '-') { neg = true; c = readByte(); }
            long val = 0; while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val; }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

